const body = $input.item.json.body || {};
const filters = body.filters || {};

const page = parseInt(body.page) || 1;
const pageSize = parseInt(body.pageSize) || 10;
const offset = (page - 1) * pageSize;

const params = [];
let paramIndex = 1;
let whereClause = 'WHERE 1=1';

if (
  filters.searchText &&
  typeof filters.searchText === 'string' &&
  filters.searchText.trim() !== ''
) {
  whereClause += `
    AND (
      e.nombre_empresa ILIKE $${paramIndex}
      OR CONCAT(t.nombre, ' ', t.primer_apellido) ILIKE $${paramIndex}
    )
  `;
  params.push(`%${filters.searchText}%`);
  paramIndex++;
}

if (
  filters.id_empresa !== undefined &&
  filters.id_empresa !== null &&
  filters.id_empresa !== ''
) {
  whereClause += ` AND a.id_empresa = $${paramIndex}`;
  params.push(filters.id_empresa);
  paramIndex++;
}

if (
  filters.id_trabajador !== undefined &&
  filters.id_trabajador !== null &&
  filters.id_trabajador !== ''
) {
  whereClause += ` AND a.id_trabajador = $${paramIndex}`;
  params.push(filters.id_trabajador);
  paramIndex++;
}

if (
  filters.id_comerciales !== undefined &&
  filters.id_comerciales !== null &&
  filters.id_comerciales !== ''
) {
  whereClause += ` AND a.id_comerciales = $${paramIndex}`;
  params.push(filters.id_comerciales);
  paramIndex++;
}

if (
  filters.activo !== undefined &&
  filters.activo !== null &&
  filters.activo !== ''
) {
  whereClause += ` AND a.activo = $${paramIndex}`;
  params.push(filters.activo);
  paramIndex++;
}

// PaginaciÃ³n
params.push(pageSize);
const limitParam = paramIndex++;

params.push(offset);
const offsetParam = paramIndex++;

// Query principal
const query = `
WITH total_count AS (
  SELECT COUNT(DISTINCT a.id) AS total
  FROM asignacion a
  LEFT JOIN empresa e ON e.id = a.id_empresa
  LEFT JOIN trabajador t ON t.id = a.id_trabajador
  LEFT JOIN comerciales c ON c.id = a.id_comerciales
  ${whereClause}
),
global_counts AS (
  SELECT 
    COUNT(*) AS total_global,
    SUM(CASE WHEN activo = true THEN 1 ELSE 0 END) AS total_activos,
    SUM(CASE WHEN activo = false THEN 1 ELSE 0 END) AS total_inactivos
  FROM asignacion
),
paginado AS (
  SELECT
    a.*,
    e.nombre_empresa,
    CONCAT(
      t.nombre,
      ' ',
      t.primer_apellido,
      COALESCE(' ' || t.segundo_apellido, '')
    ) AS trabajador_nombre,
    CONCAT(
      c.nombre,
      ' ',
      c.primer_apellido,
      COALESCE(' ' || c.segundo_apellido, '')
    ) AS comercial_nombre
  FROM asignacion a
  LEFT JOIN empresa e ON e.id = a.id_empresa
  LEFT JOIN trabajador t ON t.id = a.id_trabajador
  LEFT JOIN comerciales c ON c.id = a.id_comerciales
  ${whereClause}
  ORDER BY a.id DESC
  LIMIT $${limitParam} OFFSET $${offsetParam}
)

SELECT 
  paginado.*,
  total_count.total AS total_records,
  global_counts.total_global,
  global_counts.total_activos,
  global_counts.total_inactivos
FROM paginado, total_count, global_counts;
`;

return [
  {
    json: {
      query,
      params,
      page,
      pageSize,
    },
  },
];

