const error = $input.item.json;
const pgCode = String(error.code || '');
const rawMessage = String(error.message || 'Error desconocido');

let status = 500;
let errorType = 'Internal Server Error';
let message = rawMessage;
let code = 'DB_ERROR';

if (pgCode === '23505') {
  status = 409;
  errorType = 'Conflict';
  code = 'DUPLICATE_ENTRY';
  if (rawMessage.toLowerCase().includes('email')) {
    message = 'El correo electrÃ³nico ya se encuentra registrado.';
    code = 'EMAIL_ALREADY_EXISTS';
  } else {
    const match = rawMessage.match(/unique constraint "(.+?)"/i);
    message = match
      ? `Ya existe un registro que viola la restricciÃ³n: ${match[1]}.`
      : 'Ya existe un registro con esos datos.';
  }
} else if (pgCode === '23502') {
  status = 422;
  errorType = 'Unprocessable Entity';
  code = 'MISSING_REQUIRED_FIELD';
  const match = rawMessage.match(/column "(.+?)"/);
  const field = match ? match[1] : 'desconocido';
  message = `El campo "${field}" es obligatorio y no puede estar vacÃ­o.`;
} else if (pgCode === '23503') {
  status = 409;
  errorType = 'Conflict';
  code = 'FOREIGN_KEY_VIOLATION';
  message = 'El registro referenciado no existe o ha sido eliminado.';
} else if (pgCode === '23514') {
  status = 422;
  errorType = 'Unprocessable Entity';
  code = 'CHECK_VIOLATION';
  message = 'Los datos enviados no cumplen las restricciones requeridas.';
}

return [{ json: { status, error: errorType, message, code } }];

const jwt = require('jsonwebtoken');

const JWT_SECRET = 'passEncriptada';

const body = $json.body;

const headers = $json.headers || {};
const authHeader = headers['authorization'] || headers['Authorization'] || '';
const bodyToken  = body?.token || '';
const rawToken   = authHeader || bodyToken;

const token = rawToken.replace('Bearer ', '').trim();

if (!token) {
  return [{ json: { _authError: true, status: 401, message: 'Token no proporcionado' } }];
}

try {
  const decoded = jwt.verify(token, JWT_SECRET);
  return [{
    json: {
      ...$json,
      _auth: { id: decoded.id, email: decoded.email, role: decoded.role }
    }
  }];
} catch (err) {
  return [{ json: { _authError: true, status: 401, message: 'Token invÃ¡lido o expirado - ' + err.message } }];
}
